PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "code" varchar not null, "name" varchar not null, "line" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "customers" ("id" integer primary key autoincrement not null, "code" varchar not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "materials" ("id" integer primary key autoincrement not null, "created_at" datetime, "updated_at" datetime, "plant" varchar, "material_code" varchar, "material_description" varchar, "material_type" varchar, "material_group" varchar, "base_uom" varchar not null default 'PCS', "price" numeric not null default '0', "purchase_unit" varchar, "currency" varchar not null default 'IDR', "moq" numeric, "cn" varchar, "maker" varchar, "add_cost_import_tax" numeric, "price_update" date, "price_before" numeric);
CREATE TABLE IF NOT EXISTS "material_breakdowns" ("id" integer primary key autoincrement not null, "costing_data_id" integer not null, "material_id" integer not null, "qty_req" numeric not null default '0', "amount1" numeric not null default '0', "unit_price_basis" numeric not null default '0', "currency" varchar not null default 'IDR', "qty_moq" numeric not null default '0', "cn_type" varchar not null default 'N', "import_tax_percent" numeric not null default '0', "amount2" numeric not null default '0', "currency2" varchar not null default 'IDR', "unit_price2" numeric not null default '0', "created_at" datetime, "updated_at" datetime, "unit_price_basis_text" varchar, "id_code" varchar, "pro_code" varchar, "part_no" varchar, foreign key("costing_data_id") references "costing_data"("id") on delete cascade, foreign key("material_id") references "materials"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "cycle_time_templates" ("id" integer primary key autoincrement not null, "process" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "document_receipts" ("id" integer primary key autoincrement not null, "document_number" varchar, "received_date" date not null, "partlist_original_name" varchar not null, "partlist_file_path" varchar not null, "umh_original_name" varchar not null, "umh_file_path" varchar not null, "notes" text, "created_at" datetime, "updated_at" datetime, "cust" varchar, "model" varchar, "part_number" varchar, "part_name" varchar, "pl_date" date, "umh_date" date, "pic_eng" varchar, "pic_mkt" varchar, "send_1_date" date, "send_2_date" date, "keterangan" text);
CREATE TABLE IF NOT EXISTS "document_revisions" ("id" integer primary key autoincrement not null, "document_project_id" integer not null, "version_number" integer not null, "received_date" date not null, "pic_engineering" varchar not null, "status" varchar not null default 'pending_form_input', "cogm_generated_at" datetime, "pic_marketing" varchar, "partlist_original_name" varchar not null, "partlist_file_path" varchar not null, "umh_original_name" varchar not null, "umh_file_path" varchar not null, "notes" text, "created_at" datetime, "updated_at" datetime, "change_remark" text, "a00" varchar, "a05" varchar, "a00_received_date" date, "a05_received_date" date, "a00_document_original_name" varchar, "a00_document_file_path" varchar, "a05_document_original_name" varchar, "a05_document_file_path" varchar, "a04" varchar, "a04_received_date" date, "a04_document_original_name" varchar, "a04_document_file_path" varchar, foreign key("document_project_id") references "document_projects"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "cogm_submissions" ("id" integer primary key autoincrement not null, "document_revision_id" integer not null, "submitted_at" datetime not null, "pic_marketing" varchar not null, "cogm_value" numeric, "submitted_by" varchar, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("document_revision_id") references "document_revisions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "costing_data" ("id" integer primary key autoincrement not null, "product_id" integer not null, "customer_id" integer not null, "period" varchar not null, "wo_number" varchar, "exchange_rate_usd" numeric not null default ('15500'), "exchange_rate_jpy" numeric not null default ('103'), "lme_rate" numeric, "forecast" integer not null default ('0'), "project_period" integer not null default ('12'), "material_cost" numeric not null default ('0'), "labor_cost" numeric not null default ('0'), "overhead_cost" numeric not null default ('0'), "scrap_cost" numeric not null default ('0'), "revenue" numeric not null default ('0'), "qty_good" integer not null default ('0'), "created_at" datetime, "updated_at" datetime, "model" varchar, "assy_no" varchar, "assy_name" varchar, "line" varchar, "cycle_times" text, "tracking_revision_id" integer, foreign key("customer_id") references customers("id") on delete cascade on update no action, foreign key("product_id") references products("id") on delete cascade on update no action, foreign key("tracking_revision_id") references "document_revisions"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "unpriced_parts" ("id" integer primary key autoincrement not null, "document_revision_id" integer not null, "costing_data_id" integer, "part_number" varchar not null, "part_name" varchar, "qty" numeric not null default '0', "detected_price" numeric, "manual_price" numeric, "resolved_at" datetime, "resolution_source" varchar, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("document_revision_id") references "document_revisions"("id") on delete cascade, foreign key("costing_data_id") references "costing_data"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "document_projects" ("id" integer primary key autoincrement not null, "customer" varchar not null, "model" varchar not null, "part_number" varchar not null, "part_name" varchar not null, "project_key" varchar not null, "created_at" datetime, "updated_at" datetime, "product_id" integer, foreign key("product_id") references "products"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "business_categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "code" varchar);
CREATE TABLE IF NOT EXISTS "plants" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "code" varchar);
CREATE TABLE IF NOT EXISTS "pics" ("id" integer primary key autoincrement not null, "name" varchar not null, "type" varchar check ("type" in ('engineering', 'marketing')) not null, "created_at" datetime, "updated_at" datetime);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "products_code_unique" on "products" ("code");
CREATE UNIQUE INDEX "customers_code_unique" on "customers" ("code");
CREATE UNIQUE INDEX "document_revisions_document_project_id_version_number_unique" on "document_revisions" ("document_project_id", "version_number");
CREATE INDEX "document_revisions_status_received_date_index" on "document_revisions" ("status", "received_date");
CREATE INDEX "cogm_submissions_document_revision_id_submitted_at_index" on "cogm_submissions" ("document_revision_id", "submitted_at");
CREATE INDEX "unpriced_parts_document_revision_id_resolved_at_index" on "unpriced_parts" ("document_revision_id", "resolved_at");
CREATE INDEX "unpriced_parts_document_revision_id_part_number_index" on "unpriced_parts" ("document_revision_id", "part_number");
CREATE INDEX "document_projects_customer_model_part_number_index" on "document_projects" ("customer", "model", "part_number");
CREATE UNIQUE INDEX "document_projects_project_key_unique" on "document_projects" ("project_key");
CREATE UNIQUE INDEX "business_categories_name_unique" on "business_categories" ("name");
CREATE UNIQUE INDEX "plants_name_unique" on "plants" ("name");
CREATE UNIQUE INDEX "plants_code_unique" on "plants" ("code");
CREATE UNIQUE INDEX "business_categories_code_unique" on "business_categories" ("code");
COMMIT;
